mapper.insert:
INSERT INTO lamination_material_products (
    material_code, stock_code, material_name, usage_text,
    material_type, thickness_film, thickness_glue, size_info,
    color, shape, responsible_person, category, is_active, film_thickness
) VALUES (
    #{materialCode}, #{stockCode}, #{materialName}, #{usageText},
    #{materialType}, #{thicknessFilm}, #{thicknessGlue}, #{sizeInfo},
    #{color}, #{shape}, #{responsiblePerson}, #{category}, #{isActive}, #{filmThickness}
)

mapper.select:
SELECT DISTINCT p.* FROM lamination_material_products p
INNER JOIN lamination_material_compatibility c ON p.id = c.product_id
AND (p.material_name LIKE CONCAT('%', #{keyword}, '%') OR p.material_code LIKE CONCAT('%', #{keyword}, '%') OR p.stock_code LIKE CONCAT('%', #{keyword}, '%') OR p.color LIKE CONCAT('%', #{keyword}, '%') OR p.category LIKE CONCAT('%', #{keyword}, '%'))
AND p.material_type IN
#{type}
AND c.post_processing_step IN
#{step}
ORDER BY p.material_code ASC, p.id ASC LIMIT #{limit} OFFSET #{offset}
